mapper.select:
/*MspMapper.findMspSalePlcyInfoByOnlyOrgn 판매정책정보를 조회한다.상품과 상관없이 기관별 조회를 한다 */ SELECT PL.SALE_PLCY_CD , --판매정책코드 PL.SALE_PLCY_NM, --판매정책명 PL.SALE_STRT_DTTM, --판매시작일시 PL.SALE_END_DTTM, --판매종료일시 PL.PLCY_TYPE_CD, --정책유형코드 M:오프라인, O:온라인 PL.ORGN_TYPE, --조직유형 PL.PLCY_SCTN_CD, --정책구분코드 01:단말, 02:USIM PL.PRDT_SCTN_CD, --제품구분코 02:3G, 03:LTE PL.APPL_SCTN_CD, --적용구분코드 O:개통일, R:접수일 PL.INST_RATE, --할부이자율 PL.NEW_YN, --신규여부 PL.MNP_YN, --번호이동여부 PL.HCN_YN, --일반 기변여부 PL.HDN_YN, --우수기변여부 PL.CNFM_YN, --확정여부 PL.CNFM_ID, --확정자ID PL.CNFM_DTTM, --확정일시 PL.REGST_ID, --등록자ID PL.REGST_DTTM, --등록일시 PL.RVISN_ID, --수정자ID PL.RVISN_DTTM, --수정일시 PL.SPRT_TP, --지원금유형 ORG.ORGN_ID FROM MSP_SALE_PLCY_MST@DL_MSP PL, MSP_SALE_ORGN_MST@DL_MSP ORG WHERE TO_CHAR(SYSDATE,'yyyymmddhh24miss') BETWEEN PL.SALE_STRT_DTTM AND PL.SALE_END_DTTM --판매기간 (필수) AND PL.CNFM_YN='Y' --결제 YN (필수) AND PL.SALE_PLCY_CD = ORG.SALE_PLCY_CD AND PL.PLCY_TYPE_CD = #{plcyTypeCd} -- 오프라인:M , 직영온라인 : D AND PL.PLCY_SCTN_CD = #{plcySctnCd} -- 01:단말,02:유심 AND ORG.ORGN_ID = #{orgnId}
AND PL.PRDT_SCTN_CD = #{prdtSctnCd} -- LTE,3G
AND PL.SPRT_TP = #{sprtTp} -- KD:단말할인,PM:요금할인

/*MspMapper.findMspSaleOrgnMst 판매정책정보를 조회한다. */ SELECT PL.SALE_PLCY_CD , --판매정책코드 PL.SALE_PLCY_NM, --판매정책명 PL.SALE_STRT_DTTM, --판매시작일시 PL.SALE_END_DTTM, --판매종료일시 PL.PLCY_TYPE_CD, --정책유형코드 M:오프라인, O:온라인 PL.ORGN_TYPE, --조직유형 PL.PLCY_SCTN_CD, --정책구분코드 01:단말, 02:USIM PL.PRDT_SCTN_CD, --제품구분코 02:3G, 03:LTE PL.APPL_SCTN_CD, --적용구분코드 O:개통일, R:접수일 PL.INST_RATE, --할부이자율 PL.NEW_YN, --신규여부 PL.MNP_YN, --번호이동여부 PL.HCN_YN, --기변여부 PL.HDN_YN, --우수기변여부 PL.CNFM_YN, --확정여부 PL.CNFM_ID, --확정자ID PL.CNFM_DTTM, --확정일시 PL.REGST_ID, --등록자ID PL.REGST_DTTM, --등록일시 PL.RVISN_ID, --수정자ID PL.RVISN_DTTM, --수정일시 PL.SPRT_TP, --지원금유형 ORG.ORGN_ID FROM MSP_SALE_PLCY_MST@DL_MSP PL, MSP_SALE_ORGN_MST@DL_MSP ORG, MSP_SALE_PRDT_MST@DL_MSP PRDT WHERE TO_CHAR(SYSDATE,'yyyymmddhh24miss') BETWEEN PL.SALE_STRT_DTTM AND PL.SALE_END_DTTM --판매기간 (필수) AND PL.CNFM_YN='Y' --결제 YN (필수)
AND PL.PLCY_TYPE_CD = #{plcyTypeCd} -- 온라인:O , 오프라인:M , 직영온라인 : D
AND PL.PRDT_SCTN_CD = #{prdtSctnCd} -- LTE,3G
AND PL.PLCY_SCTN_CD = #{plcySctnCd} -- 01:단말,02:유심
AND PRDT.PRDT_ID = #{prdtId} -- 단말기ID (자급제인 경우는 SKIP 처리)
AND PL.SPRT_TP = #{sprtTp} -- KD:단말할인,PM:요금할인
AND ORG.ORGN_ID = #{orgnId}
AND PL.SALE_PLCY_NM LIKE #{salePlcyNm}
AND PL.SALE_PLCY_CD = #{salePlcyCd}
AND PL.SALE_PLCY_CD = ORG.SALE_PLCY_CD AND PL.SALE_PLCY_CD = PRDT.SALE_PLCY_CD AND ORG.SALE_PLCY_cD = PRDT.SALE_PLCY_CD

/*MspMapper.findMspSalePrdMst 판매중인 상품정보를 조회한다.(msp) */ SELECT SALE_PLCY_CD, --판매정책코드 PRDT_ID, --제품ID OLD_YN, --중고여부 NEW_CMSN_AMT, --신규수수료 MNP_CMSN_AMT, --MNP수수료 HCN_CMSN_AMT, --기변수수료 REGST_ID, --등록자ID REGST_DTTM, --등록일시 RVISN_ID, --수정자ID RVISN_DTTM --수정일시 FROM MSP_SALE_PRDT_MST@DL_MSP WHERE SALE_PLCY_CD = #{salePlcyCd}
AND PRDT_ID = #{prdtId} -- (자급제인 경우는 SKIP 처리)
AND ROWNUM = 1 -- (자급제인 경우는 1개만 조회)

/*MspMapper.listOrgnMnfctMst MSP 에서 제조사/공급사 정보를 조회한다. */ SELECT MNFCT_ID, MNFCT_NM, BIZ_REG_NUM, RPRSEN_NM, ZIPCD, ADDR, DTL_ADDR, MNFCT_YN, TELNUM, FAX, EMAIL, SERIALNO_FLG, REG_ID, REG_DTTM, RVISN_ID, RVISN_DTTM, CASE --정렬순서 를 특정값으로 강제 하기위한부분 WHEN MNFCT_ID = '0141' THEN 1 --삼성전자 WHEN MNFCT_ID = '0142' THEN 2 --LG 전자 ELSE 3 END AS TEMP_ORDER_NO FROM ORG_MNFCT_MST@DL_MSP WHERE 1 = 1 --AND MNFCT_ID IN ('0141','0142','0122')
AND MNFCT_YN = #{mnfctYn}
ORDER BY TEMP_ORDER_NO

/*MspMapper.listMspRateMst 해당정책코드에 해당하는 판매요금제 정보 리스트 조회 - 어드민 상품관리 상세화면에서 사용 */ SELECT RA.RATE_CD, --요금제코드 RA.APPL_END_DT, --적용종료일자 RA.APPL_STRT_DT, --적용시작일자 RA.RATE_NM, --요금제명 RA.RATE_GRP_CD, --요금제그룹코드 RA.PAY_CL_CD, --선후불구분 RA.RATE_TYPE, --요금제유형( ORG0008 ) RA.DATA_TYPE, --데이터유형( ORG0018 ) RA.BASE_AMT, --기본료 RA.FREE_CALL_CL_CD, --망내외무료통화구분 RA.FREE_CALL_CNT, --무료통화건수 RA.NW_IN_CALL_CNT, --망내무료통화건수 RA.NW_OUT_CALL_CNT, --망외무료통화건수 RA.FREE_SMS_CNT, --무료문자건수 RA.FREE_DATA_CNT, --무료데이터건수 RA.RMK, --비고 RA.REGST_ID, --등록자ID RA.REGST_DTTM, --등록일시 RA.RVISN_ID, --수정자ID RA.RVISN_DTTM, --수정일시 RA.ONLINE_TYPE_CD, --온라인유형코드 RA.AL_FLAG, --알요금제 구분자 RA.SERVICE_TYPE, --서비스유형 RA.CMNT, -- 요금제혜택 (SELECT SPRT_TP FROM MSP_SALE_PLCY_MST@DL_MSP WHERE SALE_PLCY_CD = #{salePlcyCd}) AS SPRT_TP FROM MSP_RATE_MST@DL_MSP RA, MSP_SALE_RATE_MST@DL_MSP SA, CMN_GRP_CD_MST@DL_MSP GR WHERE APPL_END_DT = '99991231' AND RA.PAY_CL_CD = GR.CD_VAL AND GR.GRP_ID='CMN0032' --선불후불 구분 코트값의 그룹코드 AND SA.SALE_PLCY_CD = #{salePlcyCd} AND RA.RATE_CD = SA.RATE_CD
AND RA.DATA_TYPE = #{dataType}
AND RA.PAY_CL_CD = #{payClCd}

/** MspMapper.listRateBySalePlcyCd 정책코드로 해당정책에 속해있는 요금제 리스트를 가져온다. */ SELECT RATE_MST.RATE_CD, RATE_MST.APPL_END_DT, RATE_MST.APPL_STRT_DT, RATE_MST.RATE_NM, RATE_MST.RATE_GRP_CD, RATE_MST.PAY_CL_CD, RATE_MST.RATE_TYPE, RATE_MST.DATA_TYPE, RATE_MST.BASE_AMT, RATE_MST.FREE_CALL_CL_CD, RATE_MST.FREE_CALL_CNT, RATE_MST.NW_IN_CALL_CNT, RATE_MST.NW_OUT_CALL_CNT, RATE_MST.FREE_SMS_CNT, RATE_MST.FREE_DATA_CNT, RATE_MST.RMK, RATE_MST.ONLINE_TYPE_CD, RATE_MST.AL_FLAG, RATE_MST.CMNT, -- 요금제혜택 RATE_MST.SERVICE_TYPE FROM MSP_SALE_PLCY_MST@DL_MSP PLCY, MSP_SALE_RATE_MST@DL_MSP RATE, MSP_RATE_MST@DL_MSP RATE_MST WHERE TO_CHAR(SYSDATE,'yyyymmddhh24miss') BETWEEN PLCY.SALE_STRT_DTTM AND PLCY.SALE_END_DTTM --판매기간 (필수) AND PLCY.CNFM_YN = 'Y' AND PLCY.SALE_PLCY_CD = RATE.SALE_PLCY_CD AND RATE_MST.RATE_CD = RATE.RATE_CD AND PLCY.SALE_PLCY_CD = #{salePlcyCd}
AND PAY_CL_CD = #{payClCd}
ORDER BY RATE_MST.RATE_NM

/*MspMapper.getLowPriceChargeInfoByProdList 최저가를 구하기 위한 해당 상품의 요금제 정보 1건 조회 한다..*/ SELECT SALE_PLCY_CD , RATE_CD_SU , PRDT_ID , OLD_YN , AGRM_TRM , OPER_TYPE , ORGN_ID , HNDST_AMT , SUBSD_AMT , INST_AMT , INST_CMSN , AGNCY_SUBSD_MAX , AGNCY_SUBSD_AMT , REGST_ID_SU , REGST_DTTM_SU , RVISN_ID_SU , SPRT_TP , DC_AMT , ADD_DC_AMT , RATE_CD_RA , APPL_END_DT , APPL_STRT_DT , RATE_NM , RATE_GRP_CD , PAY_CL_CD , RATE_TYPE , DATA_TYPE , BASE_AMT , FREE_CALL_CL_CD , FREE_CALL_CNT , NW_IN_CALL_CNT , NW_OUT_CALL_CNT , FREE_SMS_CNT , FREE_DATA_CNT , REGST_ID , REGST_DTTM , RVISN_ID , RVISN_DTTM , ONLINE_TYPE_CD , AL_FLAG , CMNT , SERVICE_TYPE , PLCY_SCTN_CD , ON_OFF_TYPE FROM ( SELECT SU.SALE_PLCY_CD, --판매정책코드 SU.RATE_CD AS RATE_CD_SU, --요금제코드 SU.PRDT_ID, --제품ID SU.OLD_YN, --중고여부 SU.AGRM_TRM, --약정기간 SU.OPER_TYPE, --업무유형 SU.ORGN_ID, --조직ID SU.HNDST_AMT, --단말금액(VAT포함) SU.SUBSD_AMT, --공시지원금(VAT포함) SU.INST_AMT, --할부원금(VAT포함) SU.INST_CMSN, --할부수수료(VAT포함) SU.AGNCY_SUBSD_MAX, --대리점보조금MAX(VAT포함) SU.AGNCY_SUBSD_AMT, --대리점보조금(VAT포함) SU.REGST_ID AS REGST_ID_SU, --등록자ID SU.REGST_DTTM AS REGST_DTTM_SU, --등록일시 SU.RVISN_ID AS RVISN_ID_SU, --수정자ID SU.RVISN_DTTM AS RVISN_DTTM_SU, --수정일시 SU.SPRT_TP, --지원금유형 SU.DC_AMT, --기본할인금액 SU.ADD_DC_AMT, --추가할인금액 RA.RATE_CD AS RATE_CD_RA, --요금제코드 RA.APPL_END_DT, --적용종료일자 RA.APPL_STRT_DT, --적용시작일자 RA.RATE_NM, --요금제명 RA.RATE_GRP_CD, --요금제그룹코드 RA.PAY_CL_CD, --선후불구분 RA.RATE_TYPE, --요금제유형( ORG0008 ) RA.DATA_TYPE, --데이터유형( ORG0018 ) RA.BASE_AMT, --기본료 RA.FREE_CALL_CL_CD, --망내외무료통화구분 RA.FREE_CALL_CNT, --무료통화건수 RA.NW_IN_CALL_CNT, --망내무료통화건수 RA.NW_OUT_CALL_CNT, --망외무료통화건수 RA.FREE_SMS_CNT, --무료문자건수 RA.FREE_DATA_CNT, --무료데이터건수 RA.REGST_ID, --등록자ID RA.REGST_DTTM, --등록일시 RA.RVISN_ID, --수정자ID RA.RVISN_DTTM, --수정일시 RA.ONLINE_TYPE_CD, --온라인유형코드 RA.AL_FLAG, --알요금제 구분자 RA.CMNT, -- 요금제혜택 RA.SERVICE_TYPE --서비스유형 , #{plcySctnCd} AS PLCY_SCTN_CD --정책구분코드(01:단말,02:유심) , #{onOffType} AS ON_OFF_TYPE FROM MSP_SALE_SUBSD_MST@DL_MSP SU INNER JOIN MSP_RATE_MST@DL_MSP RA ON SU.RATE_CD = RA.RATE_CD WHERE 1=1 AND TO_CHAR(SYSDATE,'yyyymmdd') BETWEEN RA.APPL_STRT_DT AND RA.APPL_END_DT -- 요금제 기간
AND SALE_PLCY_CD = #{salePlcyCd} --정책코드 할인유형과 결합시 유니크
AND RA.PAY_CL_CD = #{payClCd}
AND PRDT_ID = #{prdtId} --상품ID (자급제인 경우는 SKIP 처리)
AND OLD_YN = #{oldYn} --중고여부 AND ORGN_ID = #{orgnId} --조직코드
AND OPER_TYPE = #{operType} --가입유형
AND SU.RATE_CD = #{rateCd} --요금제코드
AND AGRM_TRM = #{agrmTrm}
AND (AGRM_TRM = #{agrmTrm} or AGRM_TRM = '0') -- 약정기간 무약정0은 기본적으로 조회한다.
ORDER BY INST_AMT ASC )A WHERE 1=1 AND ROWNUM =1

SELECT/* MspMapper.salePlcyMstList 정책정보를 조회*/ DISTINCT C.SALE_PLCY_CD , C.SALE_PLCY_NM , AG.AGRM_TRM , RA.PAY_CL_CD , C.PRDT_SCTN_CD , ORG.ORGN_ID , PRDT_IND_CD , A.PRDT_ID FROM MSP_SALE_PRDT_MST@DL_MSP A -- 정책 , CMN_INTM_MDL@DL_MSP B , MSP_SALE_PLCY_MST@DL_MSP C , MSP_RATE_MST@DL_MSP RA , MSP_SALE_RATE_MST@DL_MSP SA , MSP_SALE_ORGN_MST@DL_MSP ORG , MSP_SALE_AGRM_MST@DL_MSP AG WHERE 1=1 AND C.CNFM_YN ='Y' AND C.PLCY_SCTN_CD = 02 AND A.PRDT_ID = B.PRDT_ID AND SA.SALE_PLCY_CD = AG.SALE_PLCY_CD AND A.SALE_PLCY_CD = C.SALE_PLCY_CD AND A.SALE_PLCY_CD = SA.SALE_PLCY_CD AND RA.RATE_CD = SA.RATE_CD AND C.SALE_PLCY_CD = ORG.SALE_PLCY_CD AND TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') BETWEEN C.SALE_STRT_DTTM AND C.SALE_END_DTTM AND RA.PAY_CL_CD = 'PO' AND ORG.ORGN_ID = #{orgnId}
AND A.PRDT_ID = #{prdtId}
AND C.PRDT_SCTN_CD = #{prdtSctnCd}
AND RA.RATE_CD = #{rateCd}
AND B.PRDT_IND_CD = #{prdtIndCd}
ORDER BY AGRM_TRM ASC

/*MspMapper.listMspRateAgrm 해당정책코드에 해당하는 판매요금제 정보 리스트 조회 */ SELECT DISTINCT T1.RATE_CD , RATE_NM , SPRT_TP , T2.DATA_TYPE FROM MSP_SALE_SUBSD_MST@DL_MSP T1 ,MSP_RATE_MST@DL_MSP T2 WHERE 1=1 AND T1.RATE_CD =T2.RATE_CD AND ORGN_ID IN('1100011741','1100011744','V000019481') -- M모바일(자급제) : V000019481 , M모바일(간편가입) : 1100011744 ,M모바일(직영온라인) : 1100011741 AND SALE_PLCY_CD IN
#{item}
AND AGRM_TRM = '0'
AND AGRM_TRM <> '0'
ORDER BY RATE_NM

SELECT NCMB.COUPN_CTG_CD, NCCB.COUPN_CTG_NM, NCMB.COUPN_NO, NCMB.COUPN_AMT, TO_CHAR(TO_DATE(NCMB.PSTNG_START_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD') AS PSTNG_START_DATE, TO_CHAR(TO_DATE(NCMB.PSTNG_END_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD') AS PSTNG_END_DATE, NCMB.USE_YN, NCMB.USER_ID, NCMB.SMS_RCV_NO, NCMB.SVC_CNTR_NO, TO_CHAR(TO_DATE(MJSI.LST_COM_ACTV_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD') AS LST_COM_ACTV_DATE, NCMB.SMS_SND_YN, NCMB.SMS_SND_SUCCESS_YN, NCMB.SMS_SND_DT, TO_CHAR(TO_DATE(NCMB.COUPN_GIVE_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD') AS COUPN_GIVE_DATE, NCMB.COUPN_GIVE_DATE AS FULL_GIVE_DATE, NCMB.CRET_DT, 'M쿠폰(MB)' as COUPON_CTG_NM FROM NMCP_COUPN_MBERSHIP_BAS NCMB LEFT OUTER JOIN NMCP_COUPN_CTG_BAS nccb ON NCMB.COUPN_CTG_CD = NCCB.COUPN_CTG_CD LEFT OUTER JOIN MCP_USER_CNTR_MNG MUCM ON NCMB.SVC_CNTR_NO = MUCM.SVC_CNTR_NO and NCMB.USER_ID = MUCM.USERID LEFT OUTER JOIN MSP_JUO_SUB_INFO@DL_MSP MJSI ON MUCM.SVC_CNTR_NO = MJSI.CONTRACT_NUM
and NCCB.COUPN_CTG_CD in
#{item}
union all SELECT NCMB.COUPN_CTG_CD, NCCB.COUPN_CTG_NM, NCMB.COUPN_NO, NCMB.COUPN_AMT, TO_CHAR(TO_DATE(NCMB.PSTNG_START_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD') AS PSTNG_START_DATE, TO_CHAR(TO_DATE(NCMB.PSTNG_END_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD') AS PSTNG_END_DATE, NCMB.USE_YN, NCMB.USER_ID, NCMB.SMS_RCV_NO, NCMB.SVC_CNTR_NO, TO_CHAR(TO_DATE(MJSI.LST_COM_ACTV_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD') AS LST_COM_ACTV_DATE, NCMB.SMS_SND_YN, NCMB.SMS_SND_SUCCESS_YN, NCMB.SMS_SND_DT, TO_CHAR(TO_DATE(NCMB.COUPN_GIVE_DATE,'YYYYMMDDHH24MISS'),'YYYY-MM-DD') AS COUPN_GIVE_DATE, NCMB.COUPN_GIVE_DATE AS FULL_GIVE_DATE, NCMB.CRET_DT, '외부쿠폰(EC)' as COUPON_CTG_NM FROM NMCP_COUPN_OUTSIDE_BAS NCMB LEFT OUTER JOIN NMCP_COUPN_CTG_BAS nccb ON NCMB.COUPN_CTG_CD = NCCB.COUPN_CTG_CD LEFT OUTER JOIN MCP_USER_CNTR_MNG MUCM ON NCMB.SVC_CNTR_NO = MUCM.SVC_CNTR_NO AND NCMB.USER_ID = MUCM.USERID LEFT OUTER JOIN MSP_JUO_SUB_INFO@DL_MSP MJSI ON MUCM.SVC_CNTR_NO = MJSI.CONTRACT_NUM
and NCCB.COUPN_CTG_CD in
#{item}

mapper.insert:
/* MspMapper.insertApiTrace */

    SELECT SQ_API_TRACE.NEXTVAL@DL_MSP FROM DUAL

INSERT INTO MSP_API_TRACE@DL_MSP (
    TR_SEQ
    , API_TYPE
    , API_DTL
    , REQ_DTTM
    , REQ_URL
    , REQ_PARAM
    , CALL_DT
    , REGST_ID
    , REGST_DTTM
    , RVISN_ID
    , RVISN_DTTM
) VALUES (
    #{trSeq}
    , #{apiType}
    , #{apiDtl}
    , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
    , #{reqUrl}
    , #{reqParam}
    , TO_CHAR(SYSDATE,'YYYYMMDD')
    , #{sessionUserId}
    , SYSDATE
    , #{sessionUserId}
    , SYSDATE
)

mapper.select:
WITH MissionType AS ( SELECT msn.DTL_CD, msn.INDC_ODRG, 'X' AS MSN_STATUS FROM NMCP_CD_DTL msn WHERE msn.CD_GROUP_ID = 'FqcPlcyMsnList' AND msn.USE_YN = 'Y' ), MissionResult AS ( SELECT dlt.FQC_SEQ, msn.DTL_CD, CASE WHEN dlt.STATE_CODE = '02' THEN 'O' ELSE 'X' END AS MSN_STATUS FROM MCP_FQC_DLT dlt LEFT JOIN NMCP_CD_DTL msn ON msn.DTL_CD = dlt.MSN_TP_CD WHERE msn.CD_GROUP_ID = 'FqcPlcyMsnList' AND msn.USE_YN = 'Y' AND dlt.END_DTTM = '99991231235959' ) SELECT COUNT(DISTINCT A.FQC_SEQ) FROM MCP_FQC_BAS A INNER JOIN MCP_USER B ON B.USERID = A.USER_ID LEFT OUTER JOIN ( SELECT * FROM ( SELECT USERID, SVC_CNTR_NO, CNTR_MOBILE_NO ,ROW_NUMBER() OVER (PARTITION BY USERID ORDER BY REP_NO ASC) AS RN FROM MCP_USER_CNTR_MNG ) WHERE RN =1 ) C ON C.USERID = B.USERID LEFT OUTER JOIN MSP_JUO_SUB_INFO@DL_MSP D ON C.SVC_CNTR_NO = D.CONTRACT_NUM LEFT OUTER JOIN MissionType E ON 1 = 1 LEFT OUTER JOIN MissionResult F ON A.FQC_SEQ = F.FQC_SEQ AND E.DTL_CD = F.DTL_CD WHERE 1 = 1 AND A.END_DTTM = '99991231235959'
AND A.SYS_RDATE_DD BETWEEN #{strtDt} AND #{endDt}
AND A.USER_ID LIKE '%' || #{searchValue} || '%'
AND B.NAME LIKE '%' || #{searchValue} || '%'
AND D.CONTRACT_NUM = #{searchValue}
AND C.CNTR_MOBILE_NO LIKE '%' || #{searchValue} || '%'
AND EXISTS ( SELECT 1 FROM MCP_FQC_DLT AA WHERE AA.FQC_SEQ = A.FQC_SEQ AND AA.MSN_TP_CD = #{msnTpCd} AND AA.STATE_CODE = '02' AND AA.END_DTTM = '99991231235959' )
AND ( SELECT REGEXP_COUNT( LISTAGG(NVL(F.MSN_STATUS, 'X'), '') WITHIN GROUP (ORDER BY E.INDC_ODRG), 'O' ) FROM MissionResult F LEFT JOIN MissionType E ON F.DTL_CD = E.DTL_CD WHERE F.FQC_SEQ = A.FQC_SEQ GROUP BY F.FQC_SEQ ) = #{msnCnt}

WITH MissionType AS ( SELECT msn.DTL_CD, msn.INDC_ODRG, 'X' AS MSN_STATUS FROM NMCP_CD_DTL msn WHERE msn.CD_GROUP_ID = 'FqcPlcyMsnList' AND msn.USE_YN = 'Y' ), MissionResult AS ( SELECT dlt.FQC_SEQ, msn.DTL_CD, CASE WHEN dlt.STATE_CODE = '02' THEN 'O' ELSE 'X' END AS MSN_STATUS FROM MCP_FQC_DLT dlt LEFT JOIN NMCP_CD_DTL msn ON msn.DTL_CD = dlt.MSN_TP_CD WHERE msn.CD_GROUP_ID = 'FqcPlcyMsnList' AND msn.USE_YN = 'Y' AND dlt.END_DTTM ='99991231235959' ) SELECT A.FQC_SEQ, A.FQC_PLCY_CD, A.USER_ID, D.CONTRACT_NUM, B.NAME, LISTAGG( NVL(F.MSN_STATUS, 'X'), '' ) WITHIN GROUP (ORDER BY E.INDC_ODRG) AS MSN_STATUS, D.LST_COM_ACTV_DATE, D.SUB_STATUS FROM MCP_FQC_BAS A INNER JOIN MCP_USER B ON B.USERID = A.USER_ID LEFT OUTER JOIN ( SELECT * FROM ( SELECT USERID, SVC_CNTR_NO, CNTR_MOBILE_NO ,ROW_NUMBER() OVER (PARTITION BY USERID ORDER BY REP_NO ASC) AS RN FROM MCP_USER_CNTR_MNG ) WHERE RN =1 ) C ON C.USERID = B.USERID LEFT OUTER JOIN MSP_JUO_SUB_INFO@DL_MSP D ON C.SVC_CNTR_NO = D.CONTRACT_NUM LEFT OUTER JOIN MissionType E ON 1=1 LEFT OUTER JOIN MissionResult F ON A.FQC_SEQ = F.FQC_SEQ AND E.DTL_CD = F.DTL_CD WHERE 1=1 AND A.END_DTTM ='99991231235959'
AND A.SYS_RDATE_DD BETWEEN #{strtDt} AND #{endDt}
AND A.USER_ID LIKE '%' || #{searchValue} || '%'
AND B.NAME LIKE '%' || #{searchValue} || '%'
AND D.CONTRACT_NUM = #{searchValue}
AND C.CNTR_MOBILE_NO LIKE '%' || #{searchValue} || '%'
AND EXISTS ( SELECT 1 FROM MCP_FQC_DLT AA WHERE AA.FQC_SEQ = A.FQC_SEQ AND AA.MSN_TP_CD = #{msnTpCd} AND AA.STATE_CODE = '02' AND AA.END_DTTM = '99991231235959' )
GROUP BY A.FQC_SEQ,A.FQC_PLCY_CD,A.USER_ID, B.NAME, D.CONTRACT_NUM, D.LST_COM_ACTV_DATE, D.SUB_STATUS
HAVING 1=1 AND REGEXP_COUNT( LISTAGG( NVL(F.MSN_STATUS, 'X'), '' ) WITHIN GROUP (ORDER BY E.INDC_ODRG), 'O' ) = #{msnCnt}
ORDER BY A.FQC_SEQ DESC

WITH MissionType AS ( SELECT msn.DTL_CD, msn.INDC_ODRG, 'X' AS MSN_STATUS FROM NMCP_CD_DTL msn WHERE msn.CD_GROUP_ID = 'FqcPlcyMsnList' AND msn.USE_YN = 'Y' ), MissionResult AS ( SELECT dlt.FQC_SEQ, msn.DTL_CD, CASE WHEN dlt.STATE_CODE = '02' THEN 'O' ELSE 'X' END AS MSN_STATUS FROM MCP_FQC_DLT dlt LEFT JOIN NMCP_CD_DTL msn ON msn.DTL_CD = dlt.MSN_TP_CD WHERE msn.CD_GROUP_ID = 'FqcPlcyMsnList' AND msn.USE_YN = 'Y' AND dlt.END_DTTM ='99991231235959' ) SELECT A.FQC_SEQ, A.FQC_PLCY_CD, A.SYS_RDATE_DD, /*참여일자*/ A.USER_ID, D.CONTRACT_NUM, B.NAME, LISTAGG( NVL(F.MSN_STATUS, 'X'), '' ) WITHIN GROUP (ORDER BY E.INDC_ODRG) AS MSN_STATUS, D.LST_COM_ACTV_DATE, D.SUB_STATUS ,REGEXP_COUNT( LISTAGG( NVL(F.MSN_STATUS, 'X'), '' ) WITHIN GROUP (ORDER BY E.INDC_ODRG), 'O' ) AS MSN_CNT /*미션 달성 수*/ ,(SELECT COMMEND_ID FROM MCP_COMMEND_ID_MNG WHERE CONTRACT_NUM = D.CONTRACT_NUM) AS COMMEND_ID /*추천인ID*/ ,C.CNTR_MOBILE_NO /*연락처*/ ,TO_CHAR(TO_DATE(G.REQ_IN_DAY, 'YYYYMMDDHH24MISS'), 'YYYYMMDD') AS REQ_IN_DAY /*신청일자*/ ,G.FST_RATE_CD /*최초요금제 코드*/ ,G.FST_RATE_NM /*최초요금제 명*/ ,G.LST_RATE_CD /*현재요금제 코드*/ ,G.LST_RATE_NM /*현재요금제 명*/ ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST@DL_MSP WHERE ORGN_ID = D.OPEN_AGNT_CD) AS ORGN_NM /*대리점*/ ,(SELECT CASE WHEN MSD.REQ_USIM_SN IS NOT NULL THEN '직영온라인' ELSE FN_GET_ORGNM@DL_MSP(PUM.ORGN_ID) END FROM MSP_JUO_SUB_INFO@DL_MSP SUB2 LEFT OUTER JOIN MSP_REQUEST_DTL@DL_MSP REQ ON SUB2.CONTRACT_NUM = REQ.CONTRACT_NUM LEFT OUTER JOIN NMCP_USIM_BUY_TXN MSD ON SUB2.ICC_ID = MSD.REQ_USIM_SN LEFT OUTER JOIN MSP_PARTNER_USIM_MST@DL_MSP PUM ON REQ.FST_USIM_NO = PUM.USIM_NO WHERE SUB2.CONTRACT_NUM = D.CONTRACT_NUM AND ROWNUM =1 ) AS USIM_ORG_NM /*유심접점*/ ,(SELECT DTL_CD_NM FROM NMCP_CD_DTL WHERE CD_GROUP_ID ='NSC' AND DTL_CD = G.MOVE_COMPANY) AS MOVE_COMPANY /*이동전 통신사*/ ,(SELECT SYS_RDATE_DD FROM MCP_REQUEST_REVIEW WHERE REVIEW_ID = (SELECT REVIEW_ID FROM MCP_FQC_DLT WHERE FQC_SEQ = A.FQC_SEQ AND STATE_CODE ='02' AND REVIEW_ID !=0 AND END_DTTM = '99991231235959' AND ROWNUM =1) ) AS REVIEW_REG_DT /*사용후기 작성일자*/ ,(SELECT TO_CHAR(TO_DATE(MRK_STRT_DTTM, 'YYYYMMDDHH24MISS'), 'YYYYMMDD') FROM MCP_FQC_DLT WHERE FQC_SEQ = A.FQC_SEQ AND STATE_CODE ='02' AND END_DTTM = '99991231235959' AND MRK_STRT_DTTM IS NOT NULL AND ROWNUM =1 ) AS MRK_STRT_DTTM /*마케팅 수신동의 일자*/ ,(SELECT REG_DT FROM MDS_INET_INFO@DL_MSP WHERE STATUS ='사용중' AND INTERNET_ID = (SELECT INTERNET_ID FROM MCP_FQC_DLT WHERE FQC_SEQ = A.FQC_SEQ AND STATE_CODE ='02' AND END_DTTM = '99991231235959' AND INTERNET_ID IS NOT NULL AND ROWNUM =1 ) AND ROWNUM =1 ) AS KT_REG_DT /*KT 유선 가입일자*/ ,(SELECT OPEN_DT FROM MDS_INET_INFO@DL_MSP WHERE STATUS ='사용중' AND INTERNET_ID =(SELECT INTERNET_ID FROM MCP_FQC_DLT WHERE FQC_SEQ = A.FQC_SEQ AND STATE_CODE ='02' AND END_DTTM = '99991231235959' AND INTERNET_ID IS NOT NULL AND ROWNUM =1 ) AND ROWNUM =1 ) AS KT_OPEN_DT /*KT 유선 설치완료일자 */ FROM MCP_FQC_BAS A INNER JOIN MCP_USER B ON B.USERID = A.USER_ID LEFT OUTER JOIN ( SELECT * FROM ( SELECT USERID, SVC_CNTR_NO, CNTR_MOBILE_NO ,ROW_NUMBER() OVER (PARTITION BY USERID ORDER BY REP_NO ASC) AS RN FROM MCP_USER_CNTR_MNG ) WHERE RN =1 ) C ON C.USERID = B.USERID LEFT OUTER JOIN MSP_JUO_SUB_INFO@DL_MSP D ON C.SVC_CNTR_NO = D.CONTRACT_NUM LEFT OUTER JOIN MissionType E ON 1=1 LEFT OUTER JOIN MissionResult F ON A.FQC_SEQ = F.FQC_SEQ AND E.DTL_CD = F.DTL_CD LEFT OUTER JOIN MSP_REQUEST_DTL@DL_MSP G ON G.CONTRACT_NUM = D.CONTRACT_NUM WHERE 1=1 AND A.END_DTTM ='99991231235959'
AND A.SYS_RDATE_DD BETWEEN #{strtDt} AND #{endDt}
AND A.USER_ID LIKE '%' || #{searchValue} || '%'
AND B.NAME LIKE '%' || #{searchValue} || '%'
AND D.CONTRACT_NUM = #{searchValue}
AND C.CNTR_MOBILE_NO LIKE '%' || #{searchValue} || '%'
AND EXISTS ( SELECT 1 FROM MCP_FQC_DLT AA WHERE AA.FQC_SEQ = A.FQC_SEQ AND AA.MSN_TP_CD = #{msnTpCd} AND AA.STATE_CODE = '02' AND AA.END_DTTM = '99991231235959' )
GROUP BY A.FQC_SEQ, A.FQC_PLCY_CD, A.USER_ID, B.NAME, D.CONTRACT_NUM, D.LST_COM_ACTV_DATE, D.SUB_STATUS, A.SYS_RDATE_DD ,C.CNTR_MOBILE_NO, G.REQ_IN_DAY, G.FST_RATE_CD, G.LST_RATE_CD, D.OPEN_AGNT_CD, G.MOVE_COMPANY, G.FST_RATE_NM, G.LST_RATE_NM
HAVING 1=1 AND REGEXP_COUNT( LISTAGG( NVL(F.MSN_STATUS, 'X'), '' ) WITHIN GROUP (ORDER BY E.INDC_ODRG), 'O' ) = #{msnCnt}
ORDER BY A.FQC_SEQ DESC

/*MspMapper.getCmnGrpCdList*/
SELECT GRP_ID, CD_VAL, CD_DSC, ETC1, ETC2, ETC3, ETC4, ETC5, ETC6
FROM CMN_GRP_CD_MST@DL_MSP
WHERE GRP_ID = #{grpId}
  AND USG_YN = 'Y'

  AND CD_VAL = #{cdVal}

ORDER BY CD_VAL
